seq1 = ""  #Q9Y345
seq2 = "" #mouse [BLAST aligner detected]
seq3 = "" #rat [BLAST aligner detected]
seq4 = ""  #neutral mutations inserted 
seq5 = ""  #P02088
sequences = [seq1, seq2, seq3, seq4, seq5]
mutations_neutral = [
    (101, "G", "S"), (123, "F", "S"), (131, "A", "G"), (456, "K", "N"), (462, "D", "N"), (498, "Y", "F"), (766, "G", "R")    
]
mutations_deleterious = [
    (305, "L", "V"), (424, "T", "M"), (481, "W", "C"), (490, "Y", "C"), (508, "N", "S"), (509, "S", "R")                     
]
#buried or exposed with 10 % cutoff as used in hansa paper [0 if exposed, 1 if buried], position number[0 indexing] : 0/1 format
acess = {101 : 0, 123 : 0, 131 : 0, 456 : 0, 462 : 0, 498 : 0, 766 : 0, 306 : 0, 425 : 1, 481 : 0, 490 : 0, 508 : 1, 509 : 1}
#strucutre : 1 if part of alpha helix, 2 if part of extended strand and 0 for others
strct = {101 : 0, 123 : 0, 131 : 0, 456 : 0, 462 : 0, 498 : 1, 766 : 0, 306 : 0, 425 : 1, 481 : 0, 490 : 0, 508 : 1, 509 : 1}
#the above buried/exposed and strucutre data was obtained from "https://services.healthtech.dtu.dk/cgi-bin/webface2.cgi?jobid=6A0C46C300279D39CD285359&wait=20
delet = []
neut = []
wild = []
for num,wildtype, mutation in mutations_neutral:
    neut.append(mutation)
    wild.append(wildtype)
for num,wildtype, mutation in mutations_deleterious:
    delet.append(mutation)
    wild.append(wildtype)

def Pwild_type(pos):
    amino_acids = []
    P_Wt = {}
    for seq in sequences:
        amino_acids.append(seq[pos])
    for acid in amino_acids:
        if acid in wild:
            P_Wt[acid] = amino_acids.count(acid)/len(amino_acids)
    return P_Wt    #amino acid : number
def Pmutation(pos):
    amino_acids = []
    P_Mut = {}
    for seq in sequences:
        amino_acids.append(seq[pos])
    for acid in amino_acids:
        if acid in neut or acid in delet:
            P_Mut[acid] = amino_acids.count(acid)/len(amino_acids)
    return P_Mut      #amino acid : number

def diff_bw_P(pos, res):   #here the res is the wild type
    wildn = Pwild_type(pos)
    mutat = Pmutation(pos)
    if res in wildn:
        req_wd = wildn[res]
    else:
        req_wd = 0
    req_m = 0
    for num, wil, mut in(mutations_neutral + mutations_deleterious):
        if wil == res:
            req_m = mutat.get(mut, 0)
        else:
            req_m = 0
    return req_wd - req_m
#return P(wild_type) - P(mutations) for given position and given wild type - mutation pair

