BLOSUM62 = pd.DataFrame(matrix, index = rows, columns = cols)

def gribskov(pos, acid):             #here we can choose whichever acid we want (either wild type or mutant)
    seqs = [seq1, seq2, seq3, seq4, seq5]
    aacids = []
    for seq in seqs:
        aacids.append(seq[pos])
    score = 0
    for amacid in aacids:
        score += BLOSUM62[amacid][acid]
    return score

